#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, A, B; scanf("%lld %lld %lld", &N, &A, &B);
        long long ans = 360 + 2 * N - (A + B);
        printf("%lld\n", ans);
    }
    return 0;
}

